                    "type": "(entries: ResizeObserverEntry[]) => void",
                    "required": true,
                    "defaultValue": null,
                    "description": "Invoked, asynchronously and typically at most once per frame, when the child element resizes. With `observeParents`, `entries` carries one entry per observed ancestor as well."
